import { useState, useMemo, useCallback } from 'react';

// Shopping cart with quantity controls, derived totals, and a coupon input.
// Demonstrates state management, derived state via useMemo, stable callbacks,
// controlled input, list rendering with stable keys, and accessible labels.

const CATALOG = [
  { id: 'sku-1', name: 'Bluetooth Speaker', price: 4999 },
  { id: 'sku-2', name: 'USB-C Hub', price: 2499 },
  { id: 'sku-3', name: 'Wireless Mouse', price: 1799 },
];

const COUPONS = { SAVE10: 0.10, SAVE20: 0.20 };

function formatINR(paise) {
  return new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR' })
    .format(paise / 100);
}

export default function ShoppingCart() {
  const [items, setItems] = useState(() =>
    CATALOG.map(p => ({ ...p, qty: 0 }))
  );
  const [coupon, setCoupon] = useState('');

  const updateQty = useCallback((id, delta) => {
    setItems(prev => prev.map(it =>
      it.id === id ? { ...it, qty: Math.max(0, it.qty + delta) } : it
    ));
  }, []);

  const subtotal = useMemo(
    () => items.reduce((sum, it) => sum + it.qty * it.price, 0),
    [items]
  );

  const discount = useMemo(() => {
    const rate = COUPONS[coupon.trim().toUpperCase()] ?? 0;
    return Math.round(subtotal * rate);
  }, [subtotal, coupon]);

  const total = subtotal - discount;
  const couponValid = coupon.trim() === '' || COUPONS[coupon.trim().toUpperCase()] !== undefined;

  return (
    <section aria-labelledby='cart-title'>
      <h2 id='cart-title'>Shopping cart</h2>
      <ul>
        {items.map(item => (
          <li key={item.id}>
            <span>{item.name} — {formatINR(item.price)}</span>
            <button onClick={() => updateQty(item.id, -1)} aria-label={`Decrease ${item.name}`}>−</button>
            <span aria-live='polite'>{item.qty}</span>
            <button onClick={() => updateQty(item.id, +1)} aria-label={`Increase ${item.name}`}>+</button>
          </li>
        ))}
      </ul>

      <label>
        Coupon code
        <input
          type='text'
          value={coupon}
          onChange={e => setCoupon(e.target.value)}
          aria-invalid={!couponValid}
          aria-describedby='coupon-help'
        />
      </label>
      <div id='coupon-help'>
        {couponValid ? 'Try SAVE10 or SAVE20.' : 'Invalid coupon.'}
      </div>

      <dl>
        <dt>Subtotal</dt><dd>{formatINR(subtotal)}</dd>
        <dt>Discount</dt><dd>−{formatINR(discount)}</dd>
        <dt>Total</dt><dd>{formatINR(total)}</dd>
      </dl>
    </section>
  );
}
